import { G, T, A, O, P } from './domains.js';

export const part2 = [
  {id:127,domain:A,question:"What is network segmentation?",options:["Encrypting all network traffic","Installing a firewall on every endpoint","Merging separate networks into one flat network","Dividing a network into isolated segments"],answer:3,explanation:"Segmentation divides a network into zones (e.g., VLANs) so a breach in one segment cannot easily spread to others.",optionExplanations:["Encryption is a confidentiality control, separate from segmentation.","Host-based firewalls protect endpoints individually, not the network-level isolation of segmentation.","Merging networks is consolidation, the opposite of segmentation.","Segmentation divides a network into zones to limit lateral movement."]},
  {id:128,domain:A,question:"What is a VLAN?",options:["A VPN protocol for internet encryption","A wireless transmission standard","A logical network grouping devices by function","A physical network switch"],answer:2,explanation:"A VLAN (Virtual Local Area Network) groups devices logically, enabling segmentation without physical rewiring.",optionExplanations:["VPN protocols encrypt tunnels; a VLAN is a logical LAN partition, not encryption.","Wireless standards define radio frequencies, not logical device grouping.","A VLAN groups devices logically, regardless of physical location.","A switch is hardware; a VLAN is a logical configuration on top of it."]},
  {id:129,domain:A,question:"What is the function of an intrusion prevention system (IPS)?",options:["Passively alerting without blocking (IDS)","Creating encrypted site-to-site tunnels","Aggregating logs for forensic review","Actively blocking malicious traffic in real time"],answer:3,explanation:"Unlike an IDS (which only alerts), an IPS actively drops or blocks malicious traffic in line.",optionExplanations:["Passive alerting without blocking describes an IDS, not an IPS.","Creating encrypted tunnels describes a VPN, not an IPS.","Aggregating logs describes a SIEM, not an IPS.","An IPS sits inline and actively blocks malicious traffic in real time."]},
  {id:130,domain:A,question:"Which cloud service model provides virtualized infrastructure (servers, storage, networking) as a service?",options:["Function as a Service (FaaS)","Platform as a Service (PaaS)","Software as a Service (SaaS)","Infrastructure as a Service (IaaS)"],answer:3,explanation:"IaaS provides raw compute, storage, and networking; the customer manages OS, apps, and data.",optionExplanations:["FaaS (serverless) runs individual functions and is a subset of PaaS.","PaaS provides a platform for developers to build and deploy apps.","SaaS delivers complete applications over the internet.","IaaS provides virtualized infrastructure that the customer manages from the OS up."]},
  {id:131,domain:A,question:"What is the shared responsibility model in cloud computing?",options:["The provider secures everything, including customer data","Security duties are split between provider and customer","The customer alone secures the entire environment","It applies only to government cloud deployments"],answer:1,explanation:"In shared responsibility, the provider secures the cloud infrastructure; the customer secures what they put in the cloud.",optionExplanations:["The provider secures infrastructure, not everything; customers still secure their own data.","Shared responsibility divides duties: provider handles infrastructure, customer handles data and apps.","The customer isn't alone; the provider still secures infrastructure and virtualization.","Shared responsibility applies to all cloud deployments, not just government ones."]},
  {id:132,domain:A,question:"What is a CASB (Cloud Access Security Broker)?",options:["A hardware perimeter security appliance","A type of VPN for cloud access","A cloud-hosted antivirus scanning agent","Software enforcing policy between users and cloud services"],answer:3,explanation:"A CASB enforces policies (DLP, authentication, encryption) between cloud users and cloud services.",optionExplanations:["A hardware appliance guards a boundary but doesn't broker per-app cloud policies like a CASB.","VPNs create tunnels; a CASB inspects cloud application traffic instead.","A cloud antivirus scans for malware but doesn't broker access to cloud services.","A CASB sits between users and cloud apps, enforcing policies like DLP and MFA."]},
  {id:133,domain:A,question:"What is a software-defined perimeter (SDP)?",options:["Hiding infrastructure via per-session encrypted connections","A single VLAN spanning all devices","A physical firewall at a fixed perimeter","An SDN controller managing routing decisions"],answer:0,explanation:"SDP (zero-trust access) makes infrastructure invisible to unauthorized users and creates encrypted tunnels per session.",optionExplanations:["SDP hides infrastructure and creates encrypted per-session connections.","A VLAN spanning all devices is flat segmentation, not an identity-based perimeter.","A physical firewall is a fixed, static perimeter; SDP is dynamic and per-session.","SDN controllers manage routing; SDP instead controls access based on identity and trust."]},
  {id:134,domain:A,question:"Which of the following is a key principle of Zero Trust architecture?",options:["Unrestricted lateral movement after perimeter authentication","Implicit trust for users inside the network","Never trust, always verify every request","Replacing many firewalls with one gateway"],answer:2,explanation:"Zero Trust eliminates implicit trust — every access request must be authenticated and authorized regardless of origin.",optionExplanations:["Allowing unrestricted movement is the opposite of Zero Trust.","Trusting internal users by default is the traditional model Zero Trust rejects.","Zero Trust requires continuous verification of every request regardless of origin.","Reducing firewalls is architectural simplification, not a Zero Trust principle."]},
  {id:135,domain:A,question:"What is a stateful firewall?",options:["Filtering traffic only by IP address","Tracking connection state to allow return traffic","Allowing only inbound traffic from outside","Deep packet inspection at the application layer"],answer:1,explanation:"A stateful firewall tracks connection state tables and permits return traffic that belongs to established sessions.",optionExplanations:["Filtering only by IP describes basic packet filtering, not stateful inspection.","A stateful firewall tracks connection state to permit legitimate return traffic.","Allowing only inbound traffic would block outbound communication entirely.","Deep packet inspection at Layer 7 is an NGFW feature, not basic stateful inspection."]},
  {id:136,domain:A,question:"What is the function of a next-generation firewall (NGFW)?",options:["Application-layer inspection with user identification","Translating private IPs to a shared public IP","Filtering traffic only by port and protocol","Terminating remote-access VPN tunnels"],answer:0,explanation:"NGFWs combine stateful inspection with DPI, application awareness, user identity, and IPS capabilities.",optionExplanations:["NGFWs inspect traffic at the application layer and identify users.","NAT is a standard router function, not an NGFW's defining capability.","Port and protocol filtering only describes a basic stateful firewall.","Terminating VPN tunnels is a VPN concentrator function, not an NGFW's core role."]},
  {id:137,domain:A,question:"What is containerization in the context of application security?",options:["Segmenting traffic using VLANs and firewalls","Virtualizing full servers via a hypervisor","Encrypting individual files at rest","Packaging an app with dependencies in an isolated environment"],answer:3,explanation:"Containers (e.g., Docker) package apps with their dependencies into isolated environments sharing the host OS kernel.",optionExplanations:["VLAN segmentation is a network control, not application packaging.","Full VMs run on a hypervisor; containers share the host kernel instead.","File encryption protects data at rest, unrelated to packaging apps.","Containers package an app with its dependencies into an isolated runtime."]},
  {id:138,domain:A,question:"What is the primary security concern with serverless computing?",options:["Insecure function code and misconfigurations","The provider can freely read customer data","Underlying servers are never automatically patched","Functions cannot have their data or code encrypted"],answer:0,explanation:"Serverless shifts OS/infra patching to the provider but the customer is responsible for secure function code and IAM.",optionExplanations:["The main risk is insecure function code and overly permissive roles.","Reputable providers have controls preventing arbitrary access to customer data.","Serverless providers automatically handle OS and infrastructure patching.","Serverless data and code can absolutely be encrypted."]},
  {id:139,domain:A,question:"Which of the following BEST describes microsegmentation?",options:["Dividing the network into a few broad zones","A dedicated firewall at every router","Encrypting small financial micro-transactions","Granular security policy per workload or flow"],answer:3,explanation:"Microsegmentation creates fine-grained security zones down to individual workloads using software-defined policies.",optionExplanations:["A few broad zones describes traditional segmentation, not microsegmentation.","Firewalls at routers provide perimeter control, not workload-level policy.","Micro-transaction encryption is a financial concept, unrelated to network security.","Microsegmentation applies granular policy down to individual workloads or flows."]},
  {id:140,domain:A,question:"What is infrastructure as code (IaC) and its main security implication?",options:["Documenting infrastructure with diagrams","Defining infrastructure via code that can replicate misconfigurations","Robotic assembly of physical servers","Encrypting administrative management protocols"],answer:1,explanation:"IaC provisions infrastructure via code (Terraform, CloudFormation); misconfigured templates can spread security flaws at scale.",optionExplanations:["Diagrams are documentation, not machine-readable infrastructure code.","IaC provisions infrastructure through code, so one flawed template can replicate errors at scale.","Physical server assembly is unrelated to defining infrastructure through code.","Encrypting management protocols is hardening, not IaC itself."]},
  {id:141,domain:A,question:"What security principle does a honeynet implement?",options:["Encrypting sensitive network segments","Providing redundant network paths for failover","Luring attackers into a decoy network","Preventing attackers from entering the production network"],answer:2,explanation:"A honeynet is multiple honeypots forming a fake network, used to study attacker behavior in a realistic environment.",optionExplanations:["Encryption is a confidentiality control, not a deception technology.","Redundant paths describe high availability, a different purpose than deception.","A honeynet creates a realistic decoy network to study attacker behavior.","Perimeter security aims to keep attackers out; a honeynet deliberately lets them in to observe."]},
  {id:142,domain:A,question:"What is a site-to-site VPN?",options:["A client VPN for individual remote employees","A permanent tunnel connecting two entire networks","Encrypting only web browser traffic","Relying solely on browser-based HTTPS encryption"],answer:1,explanation:"A site-to-site VPN creates a persistent encrypted tunnel between two networks, typically using IPsec.",optionExplanations:["Individual remote access describes a client-to-site VPN, not site-to-site.","A site-to-site VPN permanently links two networks with an encrypted tunnel.","Encrypting only browser traffic describes a clientless VPN, not site-to-site.","Site-to-site VPNs typically use IPsec, not just browser-based HTTPS."]},
  {id:143,domain:A,question:"Which of the following is a benefit of using HTTPS over HTTP?",options:["Encryption and authentication of web traffic","Reduced server resource usage","Faster page loading speeds","Improved database query performance"],answer:0,explanation:"HTTPS uses TLS to encrypt traffic between client and server and authenticates the server via a certificate.",optionExplanations:["HTTPS encrypts traffic and authenticates the server via certificate.","TLS processing adds overhead rather than reducing resource usage.","HTTPS adds overhead; it isn't faster than HTTP.","HTTPS secures transport; it has no effect on database performance."]},
  {id:144,domain:A,question:"What is the purpose of network address translation (NAT)?",options:["Mapping private IP addresses to a public one","Requiring 802.1X authentication before network access","Dividing a network into VLANs","Applying IPsec encryption to all traffic"],answer:0,explanation:"NAT allows multiple devices with private IPs to share public IP addresses, providing connectivity and hiding internal addresses.",optionExplanations:["NAT translates private addresses to public ones for internet access.","802.1X controls port-level access before connection; NAT remaps addresses after.","VLANs segment traffic but don't translate addresses.","IPsec encrypts traffic but doesn't translate addresses."]},
  {id:145,domain:A,question:"A company implements a WAF (Web Application Firewall). What does it primarily protect against?",options:["Malware infections on endpoint devices","Physical intrusion into the data center","Large-scale network-layer DDoS attacks","Application-layer attacks like SQL injection and XSS"],answer:3,explanation:"A WAF inspects HTTP/S traffic and blocks web application attacks like SQLi, XSS, and CSRF.",optionExplanations:["Endpoint malware is addressed by EDR and antivirus, not a WAF.","Physical intrusion is addressed by physical security, not a WAF.","Network-layer DDoS is mitigated by scrubbing services, not a WAF.","A WAF inspects HTTP traffic to block attacks like SQL injection and XSS."]},
  {id:146,domain:A,question:"Which wireless attack creates an access point with the same SSID as a legitimate network to intercept traffic?",options:["Evil twin attack","War driving","Bluejacking","Deauthentication attack"],answer:0,explanation:"An evil twin AP broadcasts the same SSID as the legitimate network, tricking users into connecting to the attacker's AP.",optionExplanations:["An evil twin uses a rogue AP with the same SSID to intercept traffic.","War driving scans for open networks; it doesn't create a rogue AP.","Bluejacking is a Bluetooth attack, not Wi-Fi.","A deauth attack disconnects clients; it doesn't impersonate the AP itself."]},
  {id:147,domain:A,question:"What is the difference between IDS and IPS?",options:["IDS monitors and alerts; IPS actively blocks traffic","IPS can only protect wireless networks","IDS and IPS are functionally identical","IDS blocks traffic; IPS only alerts"],answer:0,explanation:"An IDS detects and alerts on threats; an IPS sits inline and takes active blocking action.",optionExplanations:["An IDS detects and alerts; an IPS sits inline and blocks threats.","Both IDS and IPS can protect wired or wireless networks.","IDS and IPS serve distinct purposes and are not the same.","This reverses the roles; IPS blocks, IDS only alerts."]},
  {id:148,domain:A,question:"Which of the following BEST describes an air gap?",options:["A specialized encrypted VPN tunnel","Physical isolation from all external networks","A gap between two firewall rule sets","A network relying solely on wireless connectivity"],answer:1,explanation:"An air gap physically isolates a system so it has no network connection to external or untrusted networks.",optionExplanations:["A VPN tunnel connects networks; it doesn't physically isolate a system.","An air gap physically disconnects a system from external networks entirely.","A rule set gap is a misconfiguration, not deliberate isolation.","A wireless-only network is still connected and exposed, unlike an air gap."]},
  {id:149,domain:A,question:"What is a load balancer's role in availability and security?",options:["Encrypting traffic between backend servers","Completely replacing the need for firewalls","Independently authenticating every user","Distributing traffic and filtering malicious requests"],answer:3,explanation:"Load balancers improve availability by distributing traffic and can perform SSL offloading and basic filtering.",optionExplanations:["Load balancers can offload SSL but don't encrypt traffic between backend servers themselves.","Load balancers complement firewalls but don't replace their access-control function.","Authentication is handled by IAM systems, not a load balancer.","Load balancers distribute traffic across servers and can filter malicious requests."]},
  {id:150,domain:A,question:"What is the primary purpose of network access control (NAC)?",options:["Encrypting wireless traffic between clients and APs","Blocking all external traffic from the internet","Verifying device security posture before network access","Badge-controlled physical access to server rooms"],answer:2,explanation:"NAC checks device health (OS version, patches, AV status) before granting network access.",optionExplanations:["Wireless encryption is handled by WPA2/WPA3, separate from NAC.","Blocking external traffic is a firewall function, not NAC.","NAC checks device posture, like patch level and antivirus status, before granting access.","Physical access control is handled by badges and guards, not NAC."]},
  {id:151,domain:A,question:"Which protocol is used to securely transfer files between systems?",options:["TFTP","FTP","HTTP","SFTP"],answer:3,explanation:"SFTP (SSH File Transfer Protocol) runs over SSH and provides encrypted file transfer.",optionExplanations:["TFTP is a minimal protocol with no authentication or encryption.","FTP transfers files in plaintext with no protection.","HTTP transfers web content and is unencrypted by default.","SFTP encrypts the entire session, including credentials and data, via SSH."]},
  {id:152,domain:A,question:"What is port security on a network switch?",options:["Enabling VLAN tagging on every switch port","Restricting which MAC addresses can use a port","Blocking unused ports at the perimeter firewall","Encrypting data passing through switch ports"],answer:1,explanation:"Port security limits the MAC addresses allowed on each switch port, preventing unauthorized devices from connecting.",optionExplanations:["VLAN tagging is a segmentation configuration, not port security.","Port security limits which MAC addresses may connect to a switch port.","Blocking unused ports via firewall is a perimeter measure, not switch-level port security.","Switches don't encrypt traffic; encryption happens at higher layers."]},
  {id:153,domain:A,question:"What is the purpose of DNSSEC?",options:["Providing private DNS resolution internally","Replacing DNS with a new protocol","Adding digital signatures to DNS records","Encrypting DNS queries in transit"],answer:2,explanation:"DNSSEC signs DNS records so resolvers can verify records haven't been tampered with, preventing cache poisoning.",optionExplanations:["Private internal resolution is unrelated to DNSSEC's authentication purpose.","DNSSEC extends DNS with signatures; it doesn't replace the protocol.","DNSSEC signs DNS records to prevent spoofing and cache poisoning.","DoH or DoT encrypt queries; DNSSEC instead authenticates the records."]},
  {id:154,domain:A,question:"What is the role of a proxy server in network security?",options:["Distributing dynamic IP addresses via DHCP","Intercepting and filtering traffic while hiding client identity","Establishing encrypted VPN tunnels for remote employees","Offloading TLS decryption at a load balancer"],answer:1,explanation:"A forward proxy forwards client requests, masks client IPs, and can filter or cache web content.",optionExplanations:["DHCP assigns addresses; a proxy inspects and filters traffic instead.","A proxy intercepts client requests, masks IPs, and filters content.","VPN concentrators tunnel remote users; a proxy forwards and inspects requests instead.","TLS offloading happens at a load balancer, not a forward proxy."]},
  {id:155,domain:A,question:"What is a reverse proxy?",options:["Sitting in front of backend servers to forward requests","A TLS-only proxy that rejects HTTP connections","A VPN concentrator terminating encrypted tunnels","A forward proxy hiding client IP addresses"],answer:0,explanation:"A reverse proxy accepts external connections and forwards them to internal servers, hiding backend topology.",optionExplanations:["A reverse proxy forwards external requests to backend servers.","Rejecting HTTP is a filtering choice; a reverse proxy is defined by its position in front of servers.","VPN concentrators handle remote tunnels; a reverse proxy forwards web requests.","A forward proxy hides clients; a reverse proxy serves incoming requests for servers."]},
  {id:156,domain:A,question:"Which of the following BEST describes a UTM (Unified Threat Management) appliance?",options:["A single-purpose packet-filtering firewall","A standalone intrusion prevention system","A dedicated hardware load balancer","One device combining firewall, IPS, antivirus, and VPN"],answer:3,explanation:"A UTM consolidates multiple security functions (firewall, IPS, AV, content filtering, VPN) into a single appliance.",optionExplanations:["Basic packet filtering describes a traditional firewall, not a UTM.","A standalone IPS only detects and blocks intrusions; a UTM adds much more.","A load balancer distributes traffic; a UTM is a security-focused appliance.","A UTM consolidates firewall, IPS, antivirus, filtering, and VPN into one device."]},
  {id:157,domain:A,question:"What is east-west traffic in a data center context?",options:["North-south traffic entering and leaving the data center","Traffic between the data center and cloud providers","Traffic moving laterally between servers in the data center","Traffic on the external internet"],answer:2,explanation:"East-west traffic moves between servers inside the data center; north-south traffic moves in/out of the data center.",optionExplanations:["This describes north-south traffic, the opposite of east-west.","Traffic to cloud providers is also considered north-south.","East-west traffic flows laterally between servers within the data center.","External internet traffic is north-south, not east-west."]},
  {id:158,domain:A,question:"What is the purpose of endpoint detection and response (EDR)?",options:["Providing encrypted VPN remote access","Completely replacing traditional antivirus software","Encrypting data at rest on endpoints","Monitoring endpoints and enabling threat investigation and response"],answer:3,explanation:"EDR collects telemetry from endpoints, detects advanced threats, and provides tools for investigation and automated response.",optionExplanations:["Remote access VPN connectivity is a separate solution, not EDR.","EDR complements antivirus rather than fully replacing it.","Full-disk encryption protects data at rest; EDR is a detection tool.","EDR monitors endpoint behavior and enables investigation and response to threats."]},
  {id:159,domain:A,question:"What is the function of a SIEM (Security Information and Event Management) system?",options:["Actively blocking intrusions in real time","Provisioning and deprovisioning user accounts","Collecting and correlating log data to detect events","Applying mutual TLS between security tool components"],answer:2,explanation:"SIEM aggregates logs from network, endpoints, and apps, correlating events to identify threats and generate alerts.",optionExplanations:["Real-time blocking is an IPS function, not a SIEM's.","User provisioning is an IAM function, not a SIEM's.","A SIEM collects and correlates log data from many sources to detect threats.","Encrypting tool communications is hardening, not a SIEM's core function."]},
  {id:160,domain:A,question:"What is meant by 'secure by design'?",options:["Requiring formal certifications before deployment","Building security in from the start of design","Focusing exclusively on physical security","Adding security controls after development ends"],answer:1,explanation:"Secure by design integrates security requirements into the earliest phases of architecture and development.",optionExplanations:["Certifications may be part of compliance, but that isn't secure by design.","Secure by design integrates security from the earliest architecture phase.","Physical security is only one dimension; secure by design is broader.","Bolting security on after development is the opposite of secure by design."]},
  {id:161,domain:A,question:"What is the purpose of patch management?",options:["Capturing and analyzing network packet flows","Reviewing role-based access control assignments","Creating scheduled offline backup copies","Applying updates to fix known vulnerabilities"],answer:3,explanation:"Patch management keeps systems updated to close known vulnerabilities before they can be exploited.",optionExplanations:["Traffic analysis detects anomalies but doesn't update software.","Reviewing access assignments is an IAM function, not patch management.","Backups enable recovery but don't fix vulnerabilities.","Patch management applies updates to remediate known vulnerabilities."]},
  {id:162,domain:A,question:"Which of the following BEST describes an application whitelist?",options:["A firewall rule permitting HTTP and HTTPS traffic","A list of approved applications permitted to run","A catalog of prohibited software titles","An access list of permitted IP addresses"],answer:1,explanation:"Application whitelisting allows only pre-approved executables to run, blocking all others by default.",optionExplanations:["A firewall rule controls network traffic, not which programs may execute.","An application whitelist permits only pre-approved software to run.","A list of blocked software is a blacklist, the opposite of a whitelist.","An IP allowlist restricts network connectivity, not application execution."]},
  {id:163,domain:A,question:"What is the purpose of a sandbox in security?",options:["Executing untrusted code in an isolated environment","Blocking known malware signatures at the email gateway","Encrypting sensitive files before storage","Storing malware samples in a digital repository"],answer:0,explanation:"A sandbox isolates suspicious code so it can run and be analyzed without risking the production environment.",optionExplanations:["A sandbox isolates and observes suspicious code execution.","Signature blocking at a gateway is separate from actively running code to observe it.","File encryption protects confidentiality, not code isolation.","Storing samples for reference differs from actively analyzing code in a sandbox."]},
  {id:164,domain:A,question:"What is a software bill of materials (SBOM)?",options:["A procurement document listing software licensing fees","A list of all software components and dependencies","A version history of code modifications","An automated vulnerability scan report"],answer:1,explanation:"An SBOM lists all open-source and third-party components in a product, enabling vulnerability tracking.",optionExplanations:["Licensing documents cover costs, not technical components.","An SBOM inventories all components and dependencies in a software product.","A change log tracks code modifications, not component inventory.","A vulnerability scan identifies flaws; an SBOM catalogs components instead."]},
  {id:165,domain:O,question:"What are the six phases of the incident response lifecycle (NIST)?",options:["Triage, Escalation, Investigation, Remediation, Reporting, Closure","Identify, Protect, Detect, Respond, Recover, Learn","Preparation, Detection, Analysis, Containment, Eradication, Recovery","Plan, Do, Check, Act, Review, Improve"],answer:2,explanation:"NIST SP 800-61 defines: Preparation, Detection & Analysis, Containment/Eradication/Recovery, and Post-Incident Activity.",optionExplanations:["This describes a generic helpdesk workflow, not the NIST lifecycle.","This is the NIST Cybersecurity Framework, a different model.","NIST SP 800-61 defines these six incident response phases.","This is the ISO 27001 PDCA cycle, not incident response."]},
  {id:166,domain:O,question:"What is the purpose of containment during incident response?",options:["Formally documenting findings for legal proceedings","Preventing the incident from spreading further","Rebuilding systems from clean backup images","Identifying the underlying root cause"],answer:1,explanation:"Containment isolates affected systems to stop the spread of an attack while preserving evidence.",optionExplanations:["Legal documentation is a post-incident activity, not containment.","Containment isolates affected systems to stop the attack from spreading.","Rebuilding from backup is part of recovery, after containment.","Root cause analysis happens during detection and analysis, not containment."]},
  {id:167,domain:O,question:"What is a chain of custody in digital forensics?",options:["A list of compromised systems","The sequence of events during an attack","A documented record of who handled evidence","A forensic analysis report"],answer:2,explanation:"Chain of custody documents every person who handled evidence, ensuring its integrity for legal proceedings.",optionExplanations:["A list of compromised systems is incident tracking, not chain of custody.","An attack timeline is separate from evidence handling records.","Chain of custody documents everyone who handled evidence and when.","An analysis report summarizes findings; chain of custody tracks handling."]},
  {id:168,domain:O,question:"What is the difference between eradication and recovery in incident response?",options:["They are the same incident response phase","Eradication covers malware only; recovery covers hardware only","Recovery removes the threat; eradication restores systems","Eradication removes the threat; recovery restores systems"],answer:3,explanation:"Eradication removes all traces of the threat (malware, backdoors); recovery restores services and verifies normal operation.",optionExplanations:["They are distinct phases in the incident response lifecycle.","Both phases apply broadly, not limited to malware or hardware specifically.","This reverses the definitions of eradication and recovery.","Eradication removes the threat; recovery restores normal operation afterward."]},
  {id:169,domain:O,question:"What is vulnerability scanning?",options:["Actively exploiting discovered vulnerabilities","Reviewing source code line by line","Conducting interviews with staff about practices","Automated identification of system vulnerabilities"],answer:3,explanation:"Vulnerability scanning uses automated tools to identify known vulnerabilities without exploiting them.",optionExplanations:["Actively exploiting vulnerabilities describes penetration testing, not scanning.","Reviewing source code describes static analysis, a different technique.","Staff interviews are part of a broader audit, not automated scanning.","Vulnerability scanners automatically identify known weaknesses without exploiting them."]},
  {id:170,domain:O,question:"What is the difference between a vulnerability scan and a penetration test?",options:["A scan identifies weaknesses; a pentest exploits them","Both use automated tools to exploit weaknesses","Scans are illegal without permission; pentests are not","A pentest is automated; a scan is manual"],answer:0,explanation:"Vuln scanning finds known vulnerabilities; pen testing attempts to exploit them to demonstrate real-world impact.",optionExplanations:["A scan passively identifies weaknesses; a pentest actively exploits them.","This conflates both; scanning is passive identification, not exploitation.","Both require authorization; neither is legal without permission.","This reverses it; scans are automated, pentests combine tools with manual skill."]},
  {id:171,domain:O,question:"What is the purpose of a SOAR platform?",options:["Providing real-time threat intelligence feeds","Automating incident response workflows","Completely replacing the need for a SIEM","Storing chain-of-custody forensic evidence"],answer:1,explanation:"SOAR (Security Orchestration, Automation and Response) automates repetitive tasks and orchestrates response playbooks.",optionExplanations:["Threat intel feeds come from dedicated platforms, not SOAR itself.","SOAR automates repetitive response tasks, reducing response time.","SOAR complements a SIEM by acting on its detections, not replacing it.","Evidence storage is handled by forensic repositories, not SOAR."]},
  {id:172,domain:O,question:"What is threat hunting?",options:["Running scheduled signature-based antivirus scans","Proactively searching for threats automated tools missed","Executing predefined steps after an alert fires","Installing decoy systems to lure attackers"],answer:1,explanation:"Threat hunting is a proactive, hypothesis-driven search for adversaries that have evaded automated detection.",optionExplanations:["Signature scanning is reactive detection, not proactive hunting.","Threat hunting proactively searches for adversaries that evaded automated tools.","Executing predefined steps after an alert describes incident response, not hunting.","Deploying honeypots is passive deception, not active analyst-driven hunting."]},
  {id:173,domain:O,question:"Which of the following BEST describes a data loss prevention (DLP) solution?",options:["Backing up data to prevent loss","Encrypting all files at rest","Monitoring and controlling data transfers to prevent exfiltration","Monitoring traffic for known attack signatures"],answer:2,explanation:"DLP monitors data in use, in motion, and at rest to prevent unauthorized transfer of sensitive information.",optionExplanations:["Backups address accidental loss, not intentional exfiltration.","Encryption protects stored data but doesn't monitor data movement.","DLP monitors and controls data transfers to prevent unauthorized exfiltration.","Signature-based traffic monitoring describes IDS/IPS, not DLP."]},
  {id:174,domain:O,question:"What is the purpose of log management in security operations?",options:["A full substitute for SIEM capabilities","Encrypting log entries before archival storage","Triggering automated blocks whenever an alert fires","Collecting, storing, and analyzing logs for investigation"],answer:3,explanation:"Log management centralizes logs from all sources, enabling correlation, retention for compliance, and forensic investigation.",optionExplanations:["Log management doesn't replace SIEM correlation and alerting.","Encrypting logs is a hardening measure, not the purpose of log management.","Automated response describes SOAR, not log management itself.","Log management centralizes logs to support investigation and compliance."]},
  {id:175,domain:O,question:"What is privileged access management (PAM)?",options:["Dedicated VPN access for executives","Granting every user full administrator rights","Controlling and monitoring accounts with elevated permissions","Managing badge-based physical access controls"],answer:2,explanation:"PAM enforces least privilege for admin/service accounts, requiring justification and session recording for privileged access.",optionExplanations:["VPN access is a network control, not PAM.","Granting everyone admin rights violates least privilege, the opposite of PAM.","PAM controls and monitors accounts with elevated privileges.","Physical access badges are managed by physical security, not PAM."]},
  {id:176,domain:O,question:"What is multi-factor authentication (MFA) and why is it important?",options:["Self-service account recovery via backup email","Sharing one login among multiple team members","Entering two separate passwords sequentially","Verification from two or more factor categories"],answer:3,explanation:"MFA combines something you know, have, or are — compromising one factor alone cannot grant access.",optionExplanations:["Password recovery is an account management feature, not MFA.","Sharing credentials undermines accountability and isn't MFA.","Two passwords are still one factor type (knowledge), not true MFA.","MFA requires factors from different categories, like knowledge plus possession."]},
  {id:177,domain:O,question:"What is a playbook in the context of incident response?",options:["A curated feed of known malicious indicators","A documented step-by-step incident response procedure","A manual listing all installed software","A training curriculum for new analysts"],answer:1,explanation:"An IR playbook provides predefined, tested procedures (steps, decisions, owners) for handling specific incident types.",optionExplanations:["A threat intel feed lists indicators, not response steps.","A playbook documents step-by-step procedures for a specific incident type.","Software inventories are configuration items, not IR playbooks.","A training curriculum educates staff over time, unlike an operational playbook."]},
  {id:178,domain:O,question:"What does MTTR stand for and why does it matter?",options:["Minimum Time To Recovery (theoretical best case)","Maximum Threat Tolerance Ratio","Maximum Time To Resolve (a deadline)","Mean Time To Repair (average restoration time)"],answer:3,explanation:"MTTR measures average recovery/repair time; lower MTTR means faster incident response and reduced business impact.",optionExplanations:["This is not a standard metric or what MTTR stands for.","This is not a real metric or the actual meaning of MTTR.","MTTR measures an average, not a fixed deadline.","MTTR is Mean Time To Repair, the average time to restore a system."]},
  {id:179,domain:O,question:"What is a security baseline?",options:["An unconfigured, zero-security default state","The absolute lowest acceptable security level","A defined set of minimum security requirements","The unpatched starting point before updates"],answer:2,explanation:"A security baseline defines the minimum hardening and configuration standards all systems must meet.",optionExplanations:["A default unsecured state is the opposite of a defined baseline.","A baseline defines required minimum standards, not just a barely acceptable floor.","A security baseline specifies minimum required configuration standards.","A baseline is an ongoing standard, not tied only to pre-patch state."]},
  {id:180,domain:O,question:"What is the purpose of a forensic image?",options:["A bit-for-bit copy of storage media","Encrypting evidence drives before transfer","Scanning and removing malware before analysis","A compressed backup archive for recovery"],answer:0,explanation:"A forensic image is a bit-exact duplicate of storage media, preserving evidence while protecting the original from modification.",optionExplanations:["A forensic image is an exact bit-for-bit copy of storage media.","Encrypting the drive first would alter and corrupt the evidence.","Removing malware alters evidence and corrupts forensic integrity.","A compressed backup selects files; a forensic image captures everything exactly."]},
  {id:181,domain:O,question:"Which of the following BEST describes identity and access management (IAM)?",options:["Hashing and salting passwords before storage","Controlling physical entry with keycards and PINs","A stateful packet inspection firewall appliance","Ensuring the right people access the right resources"],answer:3,explanation:"IAM encompasses provisioning, authentication, authorization, and deprovisioning of user identities and access rights.",optionExplanations:["Password hashing protects credential storage, a narrower concept than IAM.","Physical access control manages facility entry, not digital identity and access.","A firewall controls network traffic, not identity and access management.","IAM governs who can access which resources at the right times."]},
  {id:182,domain:O,question:"What is a false positive in the context of security monitoring?",options:["A genuine attack that goes undetected","A vulnerability assessed as impossible to exploit","A thoroughly confirmed, verified security incident","An alert for benign activity flagged as malicious"],answer:3,explanation:"False positives waste analyst time responding to alerts for benign activity incorrectly classified as threats.",optionExplanations:["An undetected attack is a false negative, not a false positive.","An unexploitable vulnerability is a risk assessment issue, unrelated to alert accuracy.","A confirmed incident is a true positive, the opposite of a false positive.","A false positive incorrectly flags benign activity as malicious."]},
  {id:183,domain:O,question:"What is an SLA in the context of security operations?",options:["A contract defining service and response time expectations","A technical standard for encryption algorithms","A type of coordinated network attack","A formal software license agreement"],answer:0,explanation:"An SLA (Service Level Agreement) defines measurable service expectations such as incident response times.",optionExplanations:["An SLA defines measurable service commitments, including response times.","Encryption standards are cryptographic protocols, different from a contractual SLA.","An SLA is a contract, not any form of attack.","A software license (EULA) governs usage rights, not service performance."]},
  {id:184,domain:O,question:"What is the goal of a business continuity plan (BCP)?",options:["Keeping critical business functions running during disruption","Complying with data privacy regulations","Training employees on security awareness","Responding to active security incidents in real time"],answer:0,explanation:"A BCP identifies critical processes and provides strategies to maintain them during disasters or disruptions.",optionExplanations:["A BCP ensures critical operations continue during disruptions.","Privacy compliance is handled by dedicated programs, not a BCP.","Awareness training is an administrative control, not a BCP.","Incident response handles active incidents; a BCP covers broader continuity."]},
  {id:185,domain:O,question:"What is the difference between RTO and RPO?",options:["RTO applies to hardware; RPO applies to software","Identical metrics used interchangeably","RPO measures recovery time; RTO measures data loss","RTO is max downtime; RPO is max data loss"],answer:3,explanation:"RTO (Recovery Time Objective) = max acceptable downtime. RPO (Recovery Point Objective) = max acceptable data loss.",optionExplanations:["Both metrics apply to all resource types, not just hardware or software.","They are not interchangeable; each measures a different dimension of recovery.","This reverses the definitions of RTO and RPO.","RTO defines maximum downtime; RPO defines maximum acceptable data loss."]},
  {id:186,domain:O,question:"What is a tabletop exercise?",options:["Live testing of firewall rules against simulated attacks","A discussion-based walkthrough of incident response scenarios","A physical evacuation and intruder response rehearsal","A full activation of disaster recovery systems"],answer:1,explanation:"Tabletop exercises involve key stakeholders walking through hypothetical scenarios to identify gaps in plans.",optionExplanations:["Live network testing is technical, unlike the discussion-based tabletop format.","A tabletop exercise is a discussion-based walkthrough of a scenario.","Physical evacuation drills are safety exercises, not a tabletop exercise.","A full DR activation tests real systems, unlike a tabletop discussion."]},
  {id:187,domain:O,question:"What is full disk encryption (FDE)?",options:["Encrypting the entire storage drive","Encrypting data in transit to external drives","Encrypting only specific database table columns","Encrypting only sensitive files on a disk"],answer:0,explanation:"FDE (e.g., BitLocker, FileVault) encrypts all data on the disk, protecting against physical theft.",optionExplanations:["FDE encrypts the entire drive, protecting all data if stolen.","Encrypting data in transit to external media is a different control.","Column-level encryption protects specific database fields, not the whole disk.","Encrypting only specific files is file-level encryption, not full disk encryption."]},
  {id:188,domain:O,question:"What is the purpose of a user behavior analytics (UBA) tool?",options:["Analyzing user activity to detect anomalous behavior","Tracking data volume across network segments","Automatically pushing patches to endpoint devices","Managing user identities within Active Directory"],answer:0,explanation:"UBA/UEBA establishes behavioral baselines and alerts on deviations like unusual login times or large data downloads.",optionExplanations:["UBA establishes behavioral baselines and flags deviations.","Bandwidth monitoring is network performance management, not behavior analytics.","Automated patching is patch management, not UBA.","Directory management is an IAM function, separate from behavior analytics."]},
  {id:189,domain:O,question:"What is the purpose of a security awareness training program?",options:["Specialized configuration training for network engineers","Educating all employees on threats and safe behavior","Running automated vulnerability scans on production systems","Certification exam preparation for security professionals"],answer:1,explanation:"Security awareness training reduces human-related risks by teaching employees to recognize and avoid threats.",optionExplanations:["Technical training targets IT staff, not the general workforce.","Awareness training reduces risk by teaching all employees safe behaviors.","Vulnerability scanning finds technical flaws, unrelated to employee education.","Certification prep trains individual professionals, not the whole organization."]},
  {id:190,domain:O,question:"What is the purpose of a disaster recovery plan (DRP)?",options:["Proactive controls that eliminate all outages","Technical procedures to recover IT systems after disaster","Fire drills and evacuation training for staff","Identifying and prioritizing enterprise-wide operational risks"],answer:1,explanation:"A DRP specifies how to restore IT systems and infrastructure after disasters like fires, floods, or ransomware attacks.",optionExplanations:["Preventing all outages is a risk management goal, not a DRP's purpose.","A DRP provides technical steps to restore IT systems after a disaster.","Evacuation drills are physical safety exercises, not IT recovery procedures.","Enterprise risk management addresses broader risk, not specific IT recovery steps."]},
  {id:191,domain:O,question:"Which of the following BEST describes the principle of least privilege in IAM?",options:["Expanding permissions as tenure increases","Granting only the minimum access needed for the job","Unrestricted root access for all administrators","All users sharing the same access level"],answer:1,explanation:"Least privilege minimizes the attack surface by ensuring users cannot access more than their job requires.",optionExplanations:["Seniority-based access contradicts least privilege, which ties access to job needs.","Least privilege grants only the minimum access necessary for a role.","Unrestricted admin access violates least privilege, even for IT staff.","Uniform access for everyone violates least privilege's role-based approach."]},
  {id:192,domain:O,question:"What is a security information and event management (SIEM) correlation rule?",options:["Logic combining multiple events to detect patterns","A role-based access control policy document","A firewall rule dropping known malicious IPs","AES encryption applied to log entries"],answer:0,explanation:"Correlation rules in a SIEM aggregate related events from multiple sources to detect threats that individual alerts would miss.",optionExplanations:["A correlation rule links related events to detect suspicious patterns.","An access control policy governs permissions, not event detection logic.","A firewall rule blocks traffic; a correlation rule instead analyzes log events.","Encrypting logs is a data protection measure, not detection logic."]},
  {id:193,domain:O,question:"Which of the following is a key step in identity lifecycle management?",options:["Encrypting all employee email communications","Provisioning and deprovisioning accounts as roles change","Scanning systems for known vulnerabilities","Creating and maintaining firewall rules"],answer:1,explanation:"Identity lifecycle management covers creating, modifying, and removing access rights as employees join, move, and leave.",optionExplanations:["Email encryption is a communication control, unrelated to identity lifecycle.","Provisioning and deprovisioning accounts as roles change is core to identity lifecycle management.","Vulnerability scanning is a security assessment, not identity management.","Firewall rules control network traffic, not user identity and access."]},
  {id:194,domain:O,question:"What is a rogue access point?",options:["An unauthorized access point on the corporate network","An authorized access point for guest Wi-Fi","An authorized access point with a weak password","An authorized access point on a non-standard channel"],answer:0,explanation:"A rogue AP is an unauthorized access point connected to the corporate network, creating an uncontrolled entry point.",optionExplanations:["A rogue AP is unauthorized, creating an uncontrolled entry point.","Guest Wi-Fi APs are typically authorized and isolated, unlike a rogue AP.","A weak password is a config weakness on an authorized device, not what makes it rogue.","A non-standard channel is a configuration choice, not what makes an AP rogue."]},
  {id:195,domain:O,question:"Which of the following BEST describes a cold site disaster recovery facility?",options:["A cloud service restoring backups on demand","A portable data center deployable within hours","A fully mirrored site with live data replication","Basic infrastructure with no hardware, ready in weeks"],answer:3,explanation:"A cold site has the physical infrastructure but requires significant setup time (equipment, data restore) before use.",optionExplanations:["This describes a cloud recovery service, not a cold site.","A rapidly deployable mobile facility describes a portable or warm site, not cold.","Immediate failover with live replication describes a hot site, not cold.","A cold site has infrastructure but no hardware, taking days to weeks to activate."]},
  {id:196,domain:O,question:"What is a hot site in disaster recovery?",options:["A fully mirrored facility ready for immediate failover","A portable trailer-mounted server deployment unit","A facility requiring one to three days to operate","A secondary data center in a warmer climate"],answer:0,explanation:"A hot site mirrors the production environment and can take over within minutes to hours of a disaster.",optionExplanations:["A hot site mirrors production systems for near-instant failover.","A mobile unit describes a portable recovery option, not a fixed hot site.","Requiring one to three days describes a warm site, not a hot site.","Climate has no bearing on DR site classification; readiness does."]},
  {id:197,domain:O,question:"What is the purpose of change management in IT security?",options:["Maintaining an updated network topology diagram","Ensuring changes are reviewed, tested, and approved","Updating HR records when employees transfer","Auto-installing patches without approval"],answer:1,explanation:"Change management prevents unauthorized or poorly tested changes from introducing vulnerabilities or outages.",optionExplanations:["Topology diagrams are configuration documentation, not change management itself.","Change management requires review, testing, and approval before changes go live.","HR record updates are personnel management, not IT change management.","Auto-applying patches without review bypasses change management controls."]},
  {id:198,domain:O,question:"Which of the following BEST describes security orchestration?",options:["Training staff individually on separate tools","Integrating and automating multiple security tools","Centralizing security logs into one system","Manually configuring each security tool by hand"],answer:1,explanation:"Orchestration connects disparate security tools via APIs to automate workflows spanning multiple systems.",optionExplanations:["Staff training is administrative, not technical tool integration.","Orchestration integrates and automates tools like SIEM, EDR, and ticketing via APIs.","Centralizing logs describes log management, not orchestration.","Manual, one-at-a-time configuration is the opposite of orchestration."]},
  {id:199,domain:O,question:"What is the function of an endpoint detection and response (EDR) tool?",options:["Blocking every executable regardless of reputation","A complete replacement for legacy antivirus","Monitoring endpoint behavior and enabling rapid response","Applying full-disk encryption to managed devices"],answer:2,explanation:"EDR collects telemetry, detects behavioral anomalies, and provides investigation tools including process trees and IOC correlation.",optionExplanations:["Blocking all executables describes strict application control, not EDR's core function.","EDR complements antivirus rather than simply replacing it.","EDR monitors behavior, detects threats, and enables investigation and response.","Full-disk encryption protects data at rest, a different control than EDR."]},
  {id:200,domain:O,question:"What is the purpose of network traffic analysis (NTA)?",options:["Maintaining a blacklist of malicious IP addresses","Configuring and replicating DNS zone records","Analyzing traffic patterns to detect threats and anomalies","Applying mandatory TLS to all internal traffic"],answer:2,explanation:"NTA (also called NDR) inspects traffic flows to detect C2 communication, lateral movement, and data exfiltration.",optionExplanations:["IP blocklisting is one specific control; NTA analyzes broader traffic patterns.","DNS zone management is a network admin task, unrelated to traffic analysis.","NTA analyzes network flow and behavior patterns to detect threats and anomalies.","Encrypting traffic is a confidentiality control, not traffic analysis."]},
  {id:201,domain:O,question:"What does a penetration tester do during the 'reconnaissance' phase?",options:["Exploiting known vulnerabilities","Covering tracks post-attack","Gathering target information via passive and active recon","Reporting findings to the client"],answer:2,explanation:"Reconnaissance is the information-gathering phase — OSINT, DNS lookups, port scanning to map the attack surface.",optionExplanations:["Exploiting vulnerabilities happens in the exploitation phase, not reconnaissance.","Covering tracks occurs after exploitation, well after reconnaissance.","Reconnaissance is the information-gathering phase using passive and active techniques.","Reporting is the final phase, after testing and exploitation."]},
  {id:202,domain:O,question:"What is the purpose of a security audit?",options:["Scanning systems for vulnerabilities automatically","Evaluating controls against a standard","Activating the incident response team","Delivering annual security awareness training"],answer:1,explanation:"A security audit provides an independent evaluation of whether controls meet defined standards or compliance requirements.",optionExplanations:["Vulnerability scanning is a technical activity, not the systematic review an audit performs.","An audit evaluates whether controls meet compliance or standard requirements.","Incident response reacts to breaches; an audit proactively evaluates controls.","Awareness training educates staff; it does not audit controls."]},
  {id:203,domain:O,question:"Which of the following BEST describes a false negative in security monitoring?",options:["A scan that finds no issues","A correctly detected real attack","An undetected real attack","A benign event flagged as an alert"],answer:2,explanation:"A false negative is a missed detection — a real threat that security tools failed to identify.",optionExplanations:["Finding no issues could be a true negative or a missed one.","A correctly detected attack is a true positive.","A false negative is a real attack that went undetected.","A benign event incorrectly flagged is a false positive."]},
  {id:204,domain:O,question:"What is the purpose of a certificate pinning?",options:["Using a hardware security module for private keys","Caching TLS session parameters","Automating OCSP/CRL revocation updates","Pinning a certificate to block MITM"],answer:3,explanation:"Certificate pinning rejects any certificate that doesn't match the pinned value, preventing attackers from substituting a fraudulent cert.",optionExplanations:["An HSM protects private keys; pinning ties an app to a specific certificate.","TLS session resumption speeds up handshakes; unrelated to pinning.","OCSP/CRL handle revocation status, not certificate pinning.","Pinning hardcodes a certificate or key, blocking fraudulent substitutes."]},
  {id:205,domain:O,question:"What is the purpose of user account deprovisioning?",options:["Creating new accounts","Assigning additional privileges","Removing all access rights after an employee departure","Resetting locked account passwords"],answer:2,explanation:"Deprovisioning removes all access rights when someone leaves or changes roles, preventing unauthorized access by former employees.",optionExplanations:["Creating accounts is provisioning, not deprovisioning.","Granting privileges is provisioning or access review.","Deprovisioning removes access rights when someone leaves or changes roles.","Password resets are routine maintenance, not deprovisioning."]},
  {id:206,domain:P,question:"What is risk management in information security?",options:["Eliminating all risk from every system and process","Reducing risk to an acceptable level","Transferring risk to an insurer","Logging every security alert"],answer:1,explanation:"Risk management is the ongoing process of identifying risks, evaluating their likelihood/impact, and deciding how to treat them.",optionExplanations:["Eliminating all risk is impossible; some residual risk always remains.","Risk management assesses and treats risk down to an acceptable level.","Risk transfer is only one treatment option, not the whole definition.","Logging alerts is operational monitoring, not risk management."]},
  {id:207,domain:P,question:"Which of the following are the four main risk treatment options?",options:["Ignore, Report, Escalate, Document","Accept, Avoid, Transfer, Mitigate","Scan, Patch, Monitor, Report","Plan, Do, Check, Act"],answer:1,explanation:"Risk treatment options: Accept (tolerate), Avoid (eliminate), Transfer (insure/outsource), Mitigate (reduce likelihood/impact).",optionExplanations:["These are process steps, not formal risk treatment options.","Accept, Avoid, Transfer, and Mitigate are the four standard risk treatments.","This describes vulnerability management activities, not risk treatment.","Plan-Do-Check-Act is the ISO PDCA management cycle."]},
  {id:208,domain:P,question:"What is a business impact analysis (BIA)?",options:["A simulated cyberattack","A detailed vendor cost and contract review","Assessing critical function impact","An automated vulnerability scan"],answer:2,explanation:"A BIA identifies critical processes, their dependencies, and quantifies downtime impact to prioritize recovery.",optionExplanations:["A pen test finds technical flaws; a BIA evaluates business impact.","A cost review examines spending; a BIA assesses disruption impact.","A BIA identifies critical processes and quantifies downtime impact.","Vulnerability scanning finds flaws; a BIA measures business impact."]},
  {id:209,domain:P,question:"What is the purpose of a risk register?",options:["Storing completed audit reports","Logging every detected security incident organization-wide","Documenting risks and treatment plans","Tracking patch deployment status"],answer:2,explanation:"A risk register is a living document cataloguing all identified risks with their ratings, owners, and treatment status.",optionExplanations:["Audit reports document compliance findings, not ongoing risk tracking.","Incident logging is a SIEM function, not a risk register's purpose.","A risk register records each risk's likelihood, impact, and treatment plan.","Patch tracking belongs to vulnerability management systems."]},
  {id:210,domain:P,question:"What is data classification?",options:["Labeling data by its sensitivity level for handling","Organizing files into folders","Scanning data for malware","Encrypting all sensitive data"],answer:0,explanation:"Data classification assigns sensitivity levels (e.g., Public, Internal, Confidential, Secret) to guide security controls.",optionExplanations:["Classification assigns sensitivity labels to guide security controls.","Folder organization is file management, not sensitivity labeling.","Malware scanning is an endpoint security task, not classification.","Encryption is applied based on classification, not classification itself."]},
  {id:211,domain:P,question:"What does GDPR primarily regulate?",options:["Software export controls","Financial reporting requirements","EU personal data protection","Critical infrastructure cybersecurity standards"],answer:2,explanation:"GDPR (General Data Protection Regulation) governs how organizations collect, process, and store EU residents' personal data.",optionExplanations:["Export controls are governed by laws like EAR/ITAR.","Financial reporting is regulated by laws like SOX, not GDPR.","GDPR governs processing of EU residents' personal data.","Critical infrastructure security is covered by laws like NIS2."]},
  {id:212,domain:P,question:"What is HIPAA primarily concerned with?",options:["Consumer credit reporting accuracy","Bank financial data security","Protecting health information","Secure software development practices"],answer:2,explanation:"HIPAA (Health Insurance Portability and Accountability Act) protects the privacy and security of PHI.",optionExplanations:["Credit reporting is regulated by the FCRA, not HIPAA.","Financial data falls under SOX, PCI DSS, or GLBA.","HIPAA mandates safeguards for protected health information.","Secure development is guided by OWASP and SDLC frameworks."]},
  {id:213,domain:P,question:"What is PCI DSS?",options:["A financial data classification scheme","A security standard for handling stored card data","A federal banking regulation","An encryption protocol for transactions"],answer:1,explanation:"PCI DSS (Payment Card Industry Data Security Standard) defines security requirements for cardholder data environments.",optionExplanations:["PCI DSS includes classification elements but isn't itself a scheme.","PCI DSS sets requirements for handling payment card data.","PCI DSS is an industry standard, not a government regulation.","PCI DSS is a broad standard; TLS is the encryption protocol."]},
  {id:214,domain:P,question:"What is the NIST Cybersecurity Framework (CSF)?",options:["Five functions: Identify, Protect, Detect, Respond, Recover","A legally mandatory federal regulation for all private-sector organizations","An encryption standard for government data","An individual security certification"],answer:0,explanation:"The NIST CSF is a voluntary risk-based framework helping organizations manage cybersecurity risk through five core functions.",optionExplanations:["The CSF organizes cybersecurity into five core functions.","The CSF is voluntary, not a mandatory regulation.","FIPS standards govern government encryption; the CSF is broader.","The CSF is an organizational framework, not a personal certification."]},
  {id:215,domain:P,question:"What is ISO 27001?",options:["A firewall configuration standard","An encryption protocol for data in transit","An international standard for building an ISMS program","A government security clearance"],answer:2,explanation:"ISO 27001 provides a framework for establishing, implementing, maintaining, and continuously improving an ISMS.",optionExplanations:["Firewall configuration is one narrow technical control.","TLS is an encryption protocol; ISO 27001 is a management standard.","ISO 27001 defines requirements for an Information Security Management System.","Security clearances are personnel designations, unrelated to ISO 27001."]},
  {id:216,domain:P,question:"What is the purpose of a security policy?",options:["Providing detailed step-by-step configuration instructions","Defining security rules and responsibilities","Automatically encrypting sensitive data","Scanning systems for vulnerabilities"],answer:1,explanation:"Security policies establish management's intent and requirements; technical standards and procedures implement them.",optionExplanations:["Configuration steps belong in technical standards, not policy.","A policy defines high-level rules and responsibilities for security.","Encryption is a control a policy may mandate, not perform.","Vulnerability testing is a technical activity guided by policy."]},
  {id:217,domain:P,question:"Which of the following BEST describes third-party risk management?",options:["Assessing vendor and partner security risk","Tracking patch compliance for all installed vendor software","Managing internal coding bug risk","Encrypting data shared with third parties"],answer:0,explanation:"Third-party risk management evaluates vendor security practices and contractual obligations to manage supply chain risk.",optionExplanations:["Third-party risk management evaluates vendor security posture and contracts.","Patch compliance is one narrow piece of vulnerability management.","Internal coding bugs are handled by software assurance programs.","Encryption is one control within a broader risk program."]},
  {id:218,domain:P,question:"What is the purpose of a privacy impact assessment (PIA)?",options:["Running full dynamic and static application vulnerability testing","Labeling data by sensitivity tier","Reviewing financial transaction logs","Assessing collection and protection of personal data"],answer:3,explanation:"A PIA (or DPIA under GDPR) identifies privacy risks in new systems or processes involving personal data.",optionExplanations:["Security testing finds vulnerabilities; a PIA looks at privacy risk.","Classification assigns sensitivity labels, not privacy impact analysis.","Transaction log review targets fraud, not privacy risk.","A PIA evaluates how personal data is collected, used, and protected."]},
  {id:219,domain:P,question:"What is the difference between a threat and a vulnerability?",options:["A vulnerability is the potential harm; a threat is only the weakness","Threats are external; vulnerabilities are internal","They are interchangeable terms","A threat causes harm; a vulnerability is the weakness"],answer:3,explanation:"Threat = actor or event that could cause harm. Vulnerability = weakness that could be exploited. Risk = threat × vulnerability × impact.",optionExplanations:["This reverses the definitions of threat and vulnerability.","Both threats and vulnerabilities can apply to internal or external systems.","A threat and a vulnerability are distinct concepts, not the same thing.","A threat can cause harm; a vulnerability is the weakness it exploits."]},
  {id:220,domain:P,question:"What is the purpose of due diligence in vendor selection?",options:["Requesting favorable pricing and payment terms from vendors","Investigating vendor security before contracting","Training third-party contractors","Pen testing vendor infrastructure"],answer:1,explanation:"Due diligence verifies that a vendor's security posture, compliance, and practices meet organizational requirements before signing.",optionExplanations:["Negotiating pricing is procurement, not security due diligence.","Due diligence investigates a vendor's security posture before signing a contract.","Training contractors doesn't verify existing vendor security practices.","Pen testing is ongoing assurance, not pre-contract due diligence."]},
  {id:221,domain:P,question:"What is a security controls assessment?",options:["Training employees on policies","Updating antivirus signatures","Verifying controls work effectively","Testing source code line by line for bugs"],answer:2,explanation:"A controls assessment determines whether security controls are properly implemented and achieving their intended objectives.",optionExplanations:["Training is a people control, not an assessment of it.","Signature updates are routine maintenance, not a formal assessment.","A controls assessment verifies controls are implemented and effective.","Code testing is QA, not a security controls assessment."]},
  {id:222,domain:P,question:"What is the purpose of a security metrics program?",options:["Measuring control effectiveness and posture","Tracking training completion rates","Auto-generating firewall and IDS rules","Deploying security agents to endpoints"],answer:0,explanation:"Security metrics provide quantitative measures (time to patch, MTTD, MTTR, percentage encrypted) to assess and communicate security effectiveness.",optionExplanations:["Security metrics quantify control effectiveness for management reporting.","Training completion is one narrow input, not the whole program.","Automated rule generation is a hardening task, not a metrics program.","Deploying agents is operational, not measuring security effectiveness."]},
  {id:223,domain:P,question:"What is an acceptable use policy (AUP)?",options:["A separate policy governing third-party vendor access","Rules defining acceptable employee technology use","A cloud provider contract","An encryption standards document"],answer:1,explanation:"An AUP defines permitted and prohibited uses of company systems, networks, and data by employees.",optionExplanations:["Vendor access policies govern third parties, not employee use.","An AUP sets expectations for appropriate use of IT resources.","Cloud contracts are vendor agreements, not internal employee policy.","Encryption requirements live in technical security standards, not an AUP."]},
  {id:224,domain:P,question:"What is a SOC 2 report?",options:["A third-party audit of a provider's controls","A findings report from an ethical hacking engagement","A firewall configuration benchmark","A federal cybersecurity certification"],answer:0,explanation:"SOC 2 (System and Organization Controls 2) is a third-party audit assessing a service provider's controls for Trust Service Criteria.",optionExplanations:["SOC 2 is an independent audit of security, availability, and privacy controls.","A pen test report lists vulnerabilities, not an audit of controls.","CIS Benchmarks cover configuration standards, not SOC 2.","SOC 2 is voluntary, not a government mandate like FedRAMP."]},
  {id:225,domain:P,question:"Which regulation focuses on protecting consumer financial data in the United States?",options:["HIPAA","PCI DSS","GLBA","GDPR"],answer:2,explanation:"GLBA (Gramm-Leach-Bliley Act) requires financial institutions to protect consumer financial information.",optionExplanations:["HIPAA protects health information, not financial data.","PCI DSS is a payment card standard, not financial privacy law.","GLBA requires financial institutions to protect consumer data.","GDPR is an EU privacy law, not US-specific financial regulation."]},
  {id:226,domain:G,question:"What is the purpose of a key management lifecycle?",options:["Tracking upcoming TLS certificate expiration dates","Governing the crypto key lifecycle","Resetting user login passwords","Authenticating users via a directory"],answer:1,explanation:"Key lifecycle management ensures keys are generated securely, distributed safely, rotated regularly, and destroyed when no longer needed.",optionExplanations:["Certificate lifecycle management is a related but separate process.","Key management covers generation, distribution, rotation, and destruction.","Password resets are IAM account maintenance, not key management.","Directory authentication uses LDAP/Kerberos, not key management."]},
  {id:227,domain:G,question:"What is the difference between authentication and authorization?",options:["Authentication verifies identity; authorization grants access","Authorization verifies identity, authentication grants access","They are the same process","Authentication is for humans; authorization is for systems"],answer:0,explanation:"Authentication proves who you are; authorization determines what you're allowed to do once identified.",optionExplanations:["Authentication proves who you are; authorization defines what you can do.","This reverses the two definitions.","They are sequential but distinct steps, not the same process.","Both apply broadly to users, services, and machine identities."]},
  {id:228,domain:T,question:"Which of the following is the MOST effective defense against ransomware?",options:["Blocking all email attachments","Antivirus software alone","Strong passwords","Air-gapped, tested backups"],answer:3,explanation:"Immutable, air-gapped backups ensure data can be restored even if ransomware encrypts all connected storage.",optionExplanations:["Blocking attachments misses other ransomware delivery methods.","Antivirus alone can't stop zero-day or fileless ransomware.","Strong passwords don't help recover encrypted data.","Air-gapped backups let you restore data without paying ransom."]},
  {id:229,domain:O,question:"What is the purpose of a tabletop exercise in incident response planning?",options:["Delivering hands-on technical tool training sessions","Discussing a scenario to find plan gaps","A live DR failover test","Automated vulnerability scanning"],answer:1,explanation:"Tabletop exercises build team familiarity with IR processes and reveal plan gaps in a low-risk discussion format.",optionExplanations:["Technical training builds skills; a tabletop tests the IR plan.","Tabletop exercises use scenarios to reveal gaps, without live systems.","A live failover activates real systems, unlike a tabletop discussion.","Vulnerability scanning is technical, not a discussion-based exercise."]},
  {id:230,domain:P,question:"What is a data retention policy?",options:["A data sensitivity classification framework","Defining how long data must be kept","An encryption algorithm standard","A backup schedule and retention plan"],answer:1,explanation:"Data retention policies define minimum and maximum periods for keeping data, balancing legal requirements with storage costs and privacy.",optionExplanations:["Classification labels data by sensitivity, not retention duration.","Retention policy defines required keep-and-delete timeframes for data.","Encryption standards secure data; retention governs its lifespan.","Backup schedules govern copies, not original record retention."]},
  {id:231,domain:G,question:"Which of the following BEST describes a pseudo-random number generator (PRNG) used in cryptography?",options:["Requiring fresh manual input each time","Producing deterministic, seed-based sequences","Using quantum phenomena as its source","Generating truly unpredictable numbers"],answer:1,explanation:"PRNGs use a seed to generate deterministic but statistically random-appearing sequences; CSPRNGs add unpredictability for crypto use.",optionExplanations:["PRNGs run algorithmically without needing manual input each time.","PRNGs generate deterministic sequences from a seed value.","Quantum RNGs are a type of true RNG, not a PRNG.","True unpredictability requires a TRNG with physical entropy, not a PRNG."]},
  {id:232,domain:G,question:"What is the purpose of a message authentication code (MAC)?",options:["Signing a message with a private key","Verifying integrity and sender with a shared secret key","Encrypting a message for confidentiality","Assigning Layer 2 hardware addresses"],answer:1,explanation:"A MAC (e.g., HMAC) uses a shared secret key to create a tag verifying both message integrity and sender authenticity.",optionExplanations:["Digital signatures use asymmetric keys; a MAC uses a shared key.","A MAC uses a shared secret key to verify integrity and sender.","MACs provide integrity and authenticity, not confidentiality.","Network MAC addresses are unrelated hardware identifiers."]},
  {id:233,domain:G,question:"What type of encryption does TLS use for the bulk of data transfer after the handshake?",options:["Asymmetric encryption exclusively","No encryption, only integrity checks","Symmetric encryption (AES) for speed","Hashing for data protection"],answer:2,explanation:"TLS uses asymmetric crypto only during the handshake to establish keys; symmetric AES encrypts the actual data.",optionExplanations:["Asymmetric encryption is used only during the handshake.","TLS provides encryption, not just integrity checking.","Symmetric AES encrypts bulk data after the handshake for speed.","Hashing provides integrity, not encryption."]},
  {id:234,domain:G,question:"What is an ephemeral key?",options:["A symmetric key shared among users","A permanent key stored in an HSM","A temporary key used for one session","A backup recovery key for emergencies"],answer:2,explanation:"Ephemeral keys are generated fresh for each session, enabling perfect forward secrecy by not persisting after session end.",optionExplanations:["Shared key distribution is separate from a key's session lifespan.","Permanent HSM-stored keys are long-term, the opposite of ephemeral.","Ephemeral keys exist only for one session, enabling forward secrecy.","Backup recovery keys are long-lived, not short-lived ephemeral keys."]},
  {id:235,domain:G,question:"Which of the following BEST describes the concept of 'security through obscurity'?",options:["Hiding system architecture as a strategy","Using secrecy as the primary control","Encrypting all documentation and diagrams","Relying on secrecy over real controls"],answer:3,explanation:"Security through obscurity hides implementation details but is not considered sufficient without actual security controls.",optionExplanations:["Hiding architecture may delay attackers but offers no real protection.","Obscurity is not a sufficient primary control on its own.","Encrypting documentation is a document control, not obscurity.","It relies on hidden design rather than sound controls, generally insufficient."]},
  {id:236,domain:T,question:"What is a drive-by download attack?",options:["Malware installed via a compromised website","Physically removing a storage device from a workstation","Clicking a malicious phishing link","Copying files from an unlocked PC"],answer:0,explanation:"Drive-by downloads exploit browser vulnerabilities to silently install malware when the user visits a compromised page.",optionExplanations:["Drive-by downloads exploit browser flaws to install malware silently.","Physical media theft requires hardware access, not remote browsing.","Phishing requires user interaction; drive-bys need none.","This is physical file theft, not a remote browser exploit."]},
  {id:237,domain:T,question:"What is an XML injection attack?",options:["Embedding scripts in web pages","Flooding a server with malformed XML","Inserting malicious XML into input","Editing server-side XML config files"],answer:2,explanation:"XML injection exploits applications that process XML input without proper validation, potentially altering data or structure.",optionExplanations:["Embedding scripts describes XSS, not XML injection.","Flooding a server describes a DoS attack, not XML injection.","XML injection alters parser behavior via malicious input.","Direct file editing needs server access, unlike an injection attack."]},
  {id:238,domain:T,question:"What is a smurf attack?",options:["Social engineering with fake IT personas","Malware hiding in security software","ICMP broadcast DDoS amplification","USB-based data exfiltration"],answer:2,explanation:"A smurf attack spoofs the victim's IP as the source in ICMP echo requests sent to a broadcast address, flooding the victim with replies.",optionExplanations:["Fake IT personas describe pretexting, not a smurf attack.","Malware in security software describes a Trojan or rootkit.","A smurf attack spoofs the victim's IP in ICMP broadcasts.","USB exfiltration is a physical data theft method."]},
  {id:239,domain:T,question:"What is the purpose of a network sniffer in a security context?",options:["Scanning for open ports","Encrypting network traffic","Capturing and analyzing packets for troubleshooting or misuse","Blocking malicious traffic automatically"],answer:2,explanation:"Sniffers (Wireshark, tcpdump) capture raw packets; used legitimately for troubleshooting, maliciously for credential theft.",optionExplanations:["Port scanning is active reconnaissance, unlike passive sniffing.","Encryption is done by protocols like TLS, not a sniffer.","A sniffer captures traffic for troubleshooting or credential theft.","Blocking traffic is a firewall/IPS function, not a sniffer's."]},
  {id:240,domain:T,question:"Which of the following BEST describes an on-path attack (formerly MITM)?",options:["A targeted executive phishing campaign","A DDoS using compromised systems","Intercepting traffic between two parties","An insider attack with elevated privileges"],answer:2,explanation:"An on-path attacker inserts themselves between client and server to eavesdrop or modify the communication.",optionExplanations:["Targeting executives describes whaling, not an on-path attack.","DDoS floods a target; on-path attacks intercept traffic.","An on-path attacker sits between parties to intercept or alter data.","An insider threat is a different actor than an on-path attacker."]},
  {id:241,domain:A,question:"What is a software-defined network (SDN)?",options:["Separating the control and data planes","Host-based packet filtering in the OS","Commodity switches running open-source OS","WPA3 encryption with centralized key management"],answer:0,explanation:"SDN decouples the control plane (network intelligence) from the data plane (packet forwarding), enabling centralized management.",optionExplanations:["SDN centralizes network control by separating it from the data plane.","A host firewall filters one machine, not the whole network fabric.","White-box switches don't inherently separate control and data planes.","WPA3 secures Wi-Fi; unrelated to SDN's architecture."]},
  {id:242,domain:A,question:"What is the purpose of a content delivery network (CDN) from a security perspective?",options:["Routing remote traffic through a VPN","Applying TLS to web server responses","Spreading traffic to absorb DDoS","Inspecting HTTP requests with a WAF"],answer:2,explanation:"CDNs distribute content globally and can absorb volumetric DDoS attacks by distributing the load across many PoPs.",optionExplanations:["VPNs secure remote access; a CDN distributes content geographically.","TLS protects data in transit; a CDN mainly distributes load.","CDNs spread traffic across many nodes, absorbing volumetric DDoS attacks.","A WAF inspects requests; a CDN mainly handles distribution and scale."]},
  {id:243,domain:A,question:"What is the function of a bastion host?",options:["A hardened gateway for internal access","A shared multi-tenant application server behind a load balancer","A centralized logging server","An offsite encrypted backup repository"],answer:0,explanation:"A bastion host is a highly secured, minimized system exposed to the internet as the only entry point to a secure internal network.",optionExplanations:["A bastion host is a hardened, single audited entry point to a network.","A shared app server hosts services, not administrative gateway access.","A log server centralizes events, not network access control.","Offsite backups store data copies, unrelated to gateway access."]},
  {id:244,domain:A,question:"Which of the following BEST describes a jump server (jump box)?",options:["A dedicated dev/test environment","A standby failover server","A host continuously scanning systems for vulnerabilities","An intermediary for secure server access"],answer:3,explanation:"A jump server acts as an intermediary that admins must authenticate to before connecting to critical servers, creating a chokepoint for auditing.",optionExplanations:["Dev/test servers support development, not administrative access.","Failover servers provide availability, not an access chokepoint.","Vulnerability scanning probes for weaknesses, not access routing.","A jump server is the required hop for admins reaching secure zones."]},
  {id:245,domain:A,question:"What is TLS inspection (SSL inspection)?",options:["Replacing TLS with a proprietary protocol","Dropping all undecryptable TLS sessions","Decrypting and re-encrypting at a proxy","Verifying websites use valid certificates"],answer:2,explanation:"TLS inspection decrypts encrypted traffic at a proxy/NGFW to inspect for malware or policy violations, then re-encrypts it.",optionExplanations:["TLS inspection uses standard TLS, not a proprietary protocol.","Blocking uninspectable traffic is a policy choice, not inspection itself.","TLS inspection decrypts traffic at a proxy, inspects it, then re-encrypts.","Certificate validation is simpler than the decrypt-inspect-reencrypt process."]},
  {id:246,domain:O,question:"What is security orchestration, automation and response (SOAR)?",options:["A signature-based passive monitoring appliance","A fully manual incident handling process","Automating security response workflows","A breach notification regulation"],answer:2,explanation:"SOAR integrates security tools, automates alert triage and playbook execution, and orchestrates responses across multiple systems.",optionExplanations:["Passive signature monitoring describes an IDS, not SOAR.","Manual handling is traditional SecOps; SOAR automates those steps.","SOAR automates and orchestrates tasks across security tools.","Breach notification rules come from laws like GDPR, not SOAR."]},
  {id:247,domain:O,question:"What is the purpose of a system hardening guide?",options:["Training users on password practices","Documenting network topology","Steps to reduce the attack surface","Automating a software deployment pipeline"],answer:2,explanation:"Hardening guides (like CIS Benchmarks) document specific configurations to disable unnecessary services and close attack vectors.",optionExplanations:["Password training is awareness education, not configuration guidance.","Topology documentation is architecture, not hardening guidance.","Hardening guides specify configs that reduce attack surface.","Automated deployment pushes changes; hardening defines what to configure."]},
  {id:248,domain:O,question:"What is a port scan and when is it used?",options:["Discovering open ports with Nmap","Configuring firewall ACLs to deny ports","Inspecting packet payloads on ports with a protocol analyzer","Probing SAN storage ports for volumes"],answer:0,explanation:"Port scanning identifies open TCP/UDP ports and the services listening, revealing the attack surface of a system.",optionExplanations:["Port scanning tools like Nmap find open ports and running services.","Blocking unauthorized ports is a firewall hardening practice.","Protocol analysis inspects specific port traffic, not broad discovery.","SAN discovery targets storage protocols, not general port scanning."]},
  {id:249,domain:O,question:"What is a security information system (SIS) in industrial control?",options:["A firewall between IT and OT","A SCADA network monitoring tool","A shutdown system preventing physical harm","A SIEM tuned for OT environments"],answer:2,explanation:"Safety instrumented systems (SIS) are independent protective systems that automatically shut down processes when unsafe conditions are detected.",optionExplanations:["IT/OT firewalls segment networks, not trigger safety shutdowns.","SCADA monitoring tracks data; SIS triggers safety actions.","A safety instrumented system shuts down processes to prevent harm.","A SIEM aggregates logs; SIS specifically triggers safety shutdowns."]},
  {id:250,domain:O,question:"Which of the following BEST describes a security configuration management (SCM) process?",options:["Provisioning, rotating, and auditing passwords across systems","Keeping systems aligned to security baselines","Recording network topology centrally","Scheduling patch deployment across endpoints"],answer:1,explanation:"SCM tracks configurations, detects drift from baselines, and ensures changes go through proper approval processes.",optionExplanations:["Credential management handles secrets, not configuration baselines.","SCM ensures systems match approved baselines and controls changes.","Topology documentation is a CMDB function, not SCM.","Patch scheduling is patch management, a narrower scope than SCM."]},
  {id:251,domain:P,question:"What is the purpose of a risk assessment?",options:["Training employees on security risks","Identifying risks for treatment decisions","Logging every security incident","Automating continuous security monitoring"],answer:1,explanation:"A risk assessment evaluates threats, vulnerabilities, and potential impacts to prioritize risk treatment decisions.",optionExplanations:["Training may result from an assessment's findings, not the process.","A risk assessment identifies, analyzes, and evaluates risk for treatment.","Incident logging is reactive documentation, not proactive assessment.","Automated monitoring is a detection control, not an assessment."]},
  {id:252,domain:P,question:"What is the concept of 'due care' in information security?",options:["Hiring red teams for annual testing","Maintaining a comprehensive risk register","Buying cyber liability insurance","Taking reasonable protective steps"],answer:3,explanation:"Due care means taking prudent, reasonable security actions — what a reasonable organization would do to protect its assets.",optionExplanations:["Annual pen testing is one practice, not the broader due care standard.","A risk register documents risks, not the standard of reasonable care.","Insurance transfers risk, rather than taking protective action.","Due care is taking reasonable steps a responsible organization would."]},
];
